"use server";

import { cookies } from "next/headers";
import { redirect } from "next/navigation";
import { createClient } from "@/lib/supabase";
import { createServiceClient } from "@/lib/supabase";
import { signupSchema, loginSchema } from "@/validations/schemas";
import { sendWelcomeEmail } from "@/services/email";

export async function signup(formData) {
  const validated = signupSchema.safeParse(
    Object.fromEntries(formData)
  );

  if (!validated.success) {
    return { error: validated.error.flatten().fieldErrors };
  }

  const { email, password, handle } = validated.data;

  const cookieStore = await cookies();
  const supabase = createClient(cookieStore);

  const { data: authData, error: authError } = await supabase.auth.signUp({
    email,
    password,
  });

  if (authError) {
    if (authError.message.includes("already registered")) {
      return { error: { email: ["This email is already registered"] } };
    }
    return { error: { _form: [authError.message] } };
  }

  const userId = authData.user?.id;
  if (!userId) {
    return { error: { _form: ["Failed to create account"] } };
  }

  const serviceClient = createServiceClient();

  const { error: profileError } = await serviceClient.from("profiles").insert({
    id: userId,
    email,
    handle,
  });

  if (profileError) {
    if (profileError.code === "23505") {
      await serviceClient.auth.admin.deleteUser(userId);
      return { error: { handle: ["This handle is already taken"] } };
    }
    await serviceClient.auth.admin.deleteUser(userId);
    return { error: { _form: ["Failed to create profile"] } };
  }

  try {
    await sendWelcomeEmail({ email, handle });
  } catch {
    // Email failure should not block signup
  }

  redirect("/dashboard");
}

export async function login(formData) {
  const validated = loginSchema.safeParse(
    Object.fromEntries(formData)
  );

  if (!validated.success) {
    return { error: validated.error.flatten().fieldErrors };
  }

  const { email, password } = validated.data;

  const cookieStore = await cookies();
  const supabase = createClient(cookieStore);

  const { error } = await supabase.auth.signInWithPassword({
    email,
    password,
  });

  if (error) {
    return { error: { _form: ["Invalid email or password"] } };
  }

  redirect("/dashboard");
}

export async function logout() {
  const cookieStore = await cookies();
  const supabase = createClient(cookieStore);
  await supabase.auth.signOut();
  redirect("/login");
}

"use server";

import { cookies } from "next/headers";
import { revalidatePath } from "next/cache";
import { createClient } from "@/lib/supabase";
import { bookmarkSchema } from "@/validations/schemas";

export async function createBookmark(formData) {
  const validated = bookmarkSchema.safeParse({
    title: formData.get("title"),
    url: formData.get("url"),
    is_public: formData.get("is_public") === "true",
  });

  if (!validated.success) {
    return { error: validated.error.flatten().fieldErrors };
  }

  const { title, url, is_public } = validated.data;

  const cookieStore = await cookies();
  const supabase = createClient(cookieStore);

  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) {
    return { error: { _form: ["Not authenticated"] } };
  }

  const { error } = await supabase.from("bookmarks").insert({
    user_id: user.id,
    title,
    url,
    is_public,
  });

  if (error) {
    return { error: { _form: ["Failed to create bookmark"] } };
  }

  revalidatePath("/dashboard");
}

export async function updateBookmark(formData) {
  const id = formData.get("id");
  if (!id) {
    return { error: { _form: ["Bookmark ID is required"] } };
  }

  const validated = bookmarkSchema.safeParse({
    title: formData.get("title"),
    url: formData.get("url"),
    is_public: formData.get("is_public") === "true",
  });

  if (!validated.success) {
    return { error: validated.error.flatten().fieldErrors };
  }

  const { title, url, is_public } = validated.data;

  const cookieStore = await cookies();
  const supabase = createClient(cookieStore);

  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) {
    return { error: { _form: ["Not authenticated"] } };
  }

  const { error } = await supabase
    .from("bookmarks")
    .update({ title, url, is_public, updated_at: new Date().toISOString() })
    .eq("id", id)
    .eq("user_id", user.id);

  if (error) {
    return { error: { _form: ["Failed to update bookmark"] } };
  }

  revalidatePath("/dashboard");
}

export async function deleteBookmark(formData) {
  const id = formData.get("id");
  if (!id) {
    return { error: { _form: ["Bookmark ID is required"] } };
  }

  const cookieStore = await cookies();
  const supabase = createClient(cookieStore);

  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) {
    return { error: { _form: ["Not authenticated"] } };
  }

  const { error } = await supabase
    .from("bookmarks")
    .delete()
    .eq("id", id)
    .eq("user_id", user.id);

  if (error) {
    return { error: { _form: ["Failed to delete bookmark"] } };
  }

  revalidatePath("/dashboard");
}

import { NextResponse } from "next/server";
import { sendWelcomeEmail } from "@/services/email";

export async function POST(request) {
  try {
    const { email, handle } = await request.json();

    if (!email || !handle) {
      return NextResponse.json(
        { error: "Email and handle are required" },
        { status: 400 }
      );
    }

    await sendWelcomeEmail({ email, handle });

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error("Error sending welcome email:", error);
    return NextResponse.json(
      { error: "Failed to send email" },
      { status: 500 }
    );
  }
}

import { createServerClient } from "@supabase/ssr";
import { NextResponse } from "next/server";

export async function middleware(request) {
  let supabaseResponse = NextResponse.next({ request });

  const supabase = createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY,
    {
      cookies: {
        getAll() {
          return request.cookies.getAll();
        },
        setAll(cookiesToSet) {
          cookiesToSet.forEach(({ name, value }) =>
            request.cookies.set(name, value)
          );
          supabaseResponse = NextResponse.next({ request });
          cookiesToSet.forEach(({ name, value, options }) =>
            supabaseResponse.cookies.set(name, value, options)
          );
        },
      },
    }
  );

  const {
    data: { user },
  } = await supabase.auth.getUser();

  const isDashboard = request.nextUrl.pathname === "/dashboard";
  const isAuthPage =
    request.nextUrl.pathname === "/login" ||
    request.nextUrl.pathname === "/signup";

  if (isDashboard && !user) {
    const url = request.nextUrl.clone();
    url.pathname = "/login";
    return NextResponse.redirect(url);
  }

  if (isAuthPage && user) {
    const url = request.nextUrl.clone();
    url.pathname = "/dashboard";
    return NextResponse.redirect(url);
  }

  return supabaseResponse;
}

export const config = {
  matcher: ["/dashboard", "/login", "/signup"],
};

