"use client";

import { useState } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { bookmarkSchema } from "@/validations/schemas";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";

export function BookmarkForm({ action, defaultValues = {}, onDone }) {
  const [serverError, setServerError] = useState(null);
  const [pending, setPending] = useState(false);

  const {
    register,
    handleSubmit,
    setValue,
    watch,
    formState: { errors },
  } = useForm({
    resolver: zodResolver(bookmarkSchema),
    values: {
      title: defaultValues.title || "",
      url: defaultValues.url || "",
      is_public: defaultValues.is_public ?? false,
    },
  });

  const isPublic = watch("is_public");

  async function onSubmit(data) {
    setPending(true);
    setServerError(null);

    const formData = new FormData();
    if (defaultValues.id) {
      formData.append("id", defaultValues.id);
    }
    formData.append("title", data.title);
    formData.append("url", data.url);
    formData.append("is_public", String(data.is_public));

    const result = await action(formData);

    if (result?.error) {
      setServerError(result.error._form?.[0] || "Something went wrong");
      setPending(false);
    } else if (!defaultValues.id) {
      onDone?.();
    }
  }

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
      <div className="space-y-2">
        <Label htmlFor="title">Title</Label>
        <Input
          id="title"
          {...register("title")}
          placeholder="My bookmark"
        />
        {errors.title && (
          <p className="text-sm text-destructive">{errors.title.message}</p>
        )}
      </div>
      <div className="space-y-2">
        <Label htmlFor="url">URL</Label>
        <Input
          id="url"
          {...register("url")}
          placeholder="https://example.com"
        />
        {errors.url && (
          <p className="text-sm text-destructive">{errors.url.message}</p>
        )}
      </div>
      <div className="flex items-center gap-3">
        <Switch
          id="is_public"
          checked={isPublic}
          onCheckedChange={(v) => setValue("is_public", v)}
        />
        <Label htmlFor="is_public">
          {isPublic ? "Public" : "Private"}
        </Label>
      </div>
      <input type="hidden" name="is_public" value={isPublic} />
      {serverError && (
        <p className="text-sm text-destructive">{serverError}</p>
      )}
      <div className="flex gap-3">
        <Button type="submit" disabled={pending}>
          {pending
            ? "Saving..."
            : defaultValues.id
              ? "Update bookmark"
              : "Add bookmark"}
        </Button>
        {onDone && (
          <Button type="button" variant="ghost" onClick={onDone}>
            Cancel
          </Button>
        )}
      </div>
    </form>
  );
}

export async function sendWelcomeEmail({ email, handle }) {
  const apiKey = process.env.RESEND_API_KEY;

  if (!apiKey) {
    console.warn("RESEND_API_KEY not configured. Skipping welcome email.");
    return;
  }

  const { Resend } = await import("resend");
  const resend = new Resend(apiKey);
  const appUrl = process.env.NEXT_PUBLIC_APP_URL || "http://localhost:3000";

  const { error } = await resend.emails.send({
    from: "Bookmarks <onboarding@resend.dev>",
    to: [email],
    subject: "Welcome to Bookmarks",
    html: `
      <div style="font-family: sans-serif; max-width: 480px; margin: 0 auto;">
        <h1 style="color: #111; font-size: 24px;">Welcome to Bookmarks!</h1>
        <p style="color: #333; font-size: 16px; line-height: 1.5;">
          Hi @${handle},
        </p>
        <p style="color: #333; font-size: 16px; line-height: 1.5;">
          Your account has been created successfully. Start saving your favorite links and share them with the world.
        </p>
        <p style="margin: 24px 0;">
          <a href="${appUrl}/dashboard" style="background-color: #111; color: white; padding: 12px 24px; text-decoration: none; border-radius: 6px; font-size: 16px; display: inline-block;">
            Go to Dashboard
          </a>
        </p>
        <p style="color: #666; font-size: 14px;">
          Your public profile: <a href="${appUrl}/${handle}" style="color: #111;">${appUrl}/${handle}</a>
        </p>
      </div>
    `,
  });

  if (error) {
    console.error("Error sending welcome email:", error);
  }
}

import { createServerClient } from "@supabase/ssr";
import { createBrowserClient } from "@supabase/ssr";
import { cookies } from "next/headers";

export function createClient(cookieStore) {
  return createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY,
    {
      cookies: {
        async getAll() {
          const store = await cookieStore;
          return store.getAll();
        },
        setAll(cookiesToSet) {
          cookiesToSet.forEach(({ name, value, options }) => {
            try {
              store.set(name, value, options);
            } catch {
              // Ignore in middleware/RSC
            }
          });
        },
      },
    }
  );
}

export function createBrowserSupabaseClient() {
  return createBrowserClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY
  );
}

export function createServiceClient() {
  const { createClient } = require("@supabase/supabase-js");
  return createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL,
    process.env.SUPABASE_SERVICE_ROLE_KEY,
    {
      auth: {
        autoRefreshToken: false,
        persistSession: false,
      },
    }
  );
}

