  }

  const userId = authData.user?.id;
  if (!userId) {
    return { error: { _form: ["Failed to create account. Please try again."] } };
  }

  // Use the RPC function (security definer) instead of service role key
  const { error: profileError } = await supabase.rpc("create_profile", {
    user_id: userId,
    user_email: email,
    user_handle: handle,
  });

  if (profileError) {
    const msg = profileError.message?.toLowerCase() || "";
    if (msg.includes("duplicate") || profileError.code === "23505") {
      return { error: { handle: ["This handle is already taken"] } };
    }
    return {
      error: {
        _form: [
          "Account created but profile setup failed. Please try logging in, or contact support.",
        ],
      },
    };
  }

  try {
    await sendWelcomeEmail({ email, handle });
  } catch {
    // Email failure should not block signup
  }

  redirect("/dashboard");
}

