NEXT_PUBLIC_SUPABASE_URL=https://your-project-id.supabase.co
REDACTED
NEXT_PUBLIC_APP_URL=http://localhost:3000
```

Get `NEXT_PUBLIC_SUPABASE_URL` and `NEXT_PUBLIC_SUPABASE_ANON_KEY` from your Supabase dashboard → **Project Settings** → **API**.

**2. Run the SQL migration** — In Supabase dashboard → **SQL Editor** → **New Query** → paste and **Run**:

```sql
CREATE TABLE IF NOT EXISTS profiles (
  id UUID PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
  email TEXT NOT NULL,
  handle TEXT NOT NULL UNIQUE,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS bookmarks (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
  title TEXT NOT NULL,
  url TEXT NOT NULL,
  is_public BOOLEAN NOT NULL DEFAULT false,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

ALTER TABLE profiles ENABLE ROW LEVEL SECURITY;
ALTER TABLE bookmarks ENABLE ROW LEVEL SECURITY;

-- RLS policies
CREATE POLICY "Public profiles are viewable by everyone" ON profiles FOR SELECT USING (true);
CREATE POLICY "Users can insert their own profile" ON profiles FOR INSERT WITH CHECK (id = auth.uid());
CREATE POLICY "Users can update their own profile" ON profiles FOR UPDATE USING (id = auth.uid());
CREATE POLICY "Users can read their own bookmarks" ON bookmarks FOR SELECT USING (user_id = auth.uid());
CREATE POLICY "Anyone can read public bookmarks" ON bookmarks FOR SELECT USING (is_public = true);
CREATE POLICY "Users can insert their own bookmarks" ON bookmarks FOR INSERT WITH CHECK (user_id = auth.uid());
CREATE POLICY "Users can update their own bookmarks" ON bookmarks FOR UPDATE USING (user_id = auth.uid());
CREATE POLICY "Users can delete their own bookmarks" ON bookmarks FOR DELETE USING (user_id = auth.uid());

CREATE OR REPLACE FUNCTION create_profile(user_id UUID, user_email TEXT, user_handle TEXT)
RETURNS VOID LANGUAGE plpgsql SECURITY DEFINER AS $$
BEGIN
  INSERT INTO profiles (id, email, handle) VALUES (user_id, user_email, user_handle);
END;
$$;

GRANT EXECUTE ON FUNCTION create_profile TO anon, authenticated;
```

**3. Stop the dev server (`Ctrl+C`), then run `npm run dev` again.**

That's it. After these two files (`.env.local` + SQL migration) are in place, both signup and bookmark creation will work.

